using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Returns the current server uptime in seconds.")]
    public static string GetUptime(
        [Description("Format: 'seconds' or 'friendly'")] string format = "seconds")
    {
        var uptime = Environment.TickCount64 / 1000.0;
        return format == "friendly"
            ? TimeSpan.FromSeconds(uptime).ToString(@"d\.hh\:mm\:ss")
            : $"{uptime:F1}s";
    }

    [McpServerTool, Description("Echoes back the input message — useful for connectivity testing.")]
    public static string Ping(
        [Description("Message to echo")] string message) =>
        $"pong: {message}";
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns current application configuration as JSON.")]
    public static string GetAppSettings() =>
        JsonSerializer.Serialize(new
        {
            version = "1.0.0",
            environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            features = new
            {
                caching = true,
                rateLimiting = false,
                maxRequestsPerMinute = 60
            }
        }, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Lists available API endpoints and their descriptions.")]
    public static string GetEndpoints() =>
        JsonSerializer.Serialize(new[]
        {
            new { path = "/mcp", description = "MCP Streamable HTTP endpoint" },
            new { path = "/health", description = "Health check" }
        }, new JsonSerializerOptions { WriteIndented = true });
}

